<script lang="ts">
import { computed, defineComponent, type PropType } from 'vue';

export const iconNamesAsList = [
    'image', 'menu', 'folder-outline', 'folder', 'bin', 'cross', 'tick', 'arrow-triangle-down', 'arrow-triangle-right', 'plus', 'user', 'refresh','filter',
    'arrow-left', 'arrow-right', 'arrow-up', 'arrow-down', 'download', 'pencil', 'home', 'calendar', 'page-text', 'settings', 'flex', 'clock', 'search',
    'cart', 'info', 'external-link', 'activity', 'scissors', 'cross-circle', 'tick-circle', 'zoom-in', 'zoom-out', 'compass', 'skein', 'eye', 'eye-crossed',
    'warning', 'play',
] as const;
export type IconName = typeof iconNamesAsList[number];

export const iconSizesAsList = [
    'small', 'mid', 'large', 'huge',
];
export type IconSize = typeof iconSizesAsList[number];

export const iconGapsAsList = [
    'none', 'right', 'left',
];
export type IconGap = typeof iconGapsAsList[number];

const sizeMapping: Record<IconSize, number> = {
    'small': 8,
    'mid': 15,
    'large': 45,
    'huge': 100,
};

export default defineComponent({
    name: 'IconComponent',

    props: {
        icon: {
            type: String as PropType<IconName>,
            required: true,
        },
        size: {
            type: String as PropType<IconSize>,
            default: 'mid',
        },
        gap: {
            type: String as PropType<IconGap>,
            default: 'none',
        },
    },

    setup(props) {
        const renderSize = sizeMapping[props.size];

        const classes = computed<Record<string, boolean>>(() => ({
            [`icon-${props.icon}`]: true,
            [`gap-${props.gap}`]: true,
        }));

        return {
            renderSize,
            classes,
        };
    },
});
</script>

